public interface ITreeType {
  void Draw(int x, int y);
}

public class TreeType : ITreeType {
  private readonly string _name;
  private readonly string _color;
  public TreeType(string name, string color) { _name = name; _color = color; }
  public void Draw(int x, int y) => Console.WriteLine($"{_name}({_color}) at {x},{y}");
}

public class TreeFactory {
  private readonly Dictionary<string, ITreeType> _cache = new();
  public ITreeType GetTreeType(string name, string color) {
    var key = $"{name}:{color}";
    if (!_cache.ContainsKey(key)) _cache[key] = new TreeType(name, color);
    return _cache[key];
  }
}

public record Tree(int X, int Y, ITreeType Type);

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Factory_ReusesFlyweightInstances() {
  var factory = new TreeFactory();
  var a = factory.GetTreeType("Oak", "Green");
  var b = factory.GetTreeType("Oak", "Green");
  Assert.AreSame(a, b);
}

[TestMethod]
public void Flyweight_UsesExtrinsicCoordinates() {
  var type = new TreeType("Pine", "DarkGreen");
  type.Draw(10, 20);
  Assert.IsTrue(true);
}
